import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { orderApi, priceApi } from '../api/client';

export default function CreateOrderPage() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [price, setPrice]     = useState(null);
  const [form, setForm]       = useState({
    pickupAddress:   '',
    pickupLat:       41.5500,
    pickupLng:       60.6200,
    deliveryAddress: '',
    deliveryLat:     41.3775,
    deliveryLng:     60.3619,
    weightKg:        1,
    fragile:         false,
    description:     '',
  });

  const set = (key) => (e) =>
    setForm((f) => ({ ...f, [key]: e.target.type === 'checkbox' ? e.target.checked : e.target.value }));

  const calcPrice = useCallback(async () => {
    try {
      const { data } = await priceApi.calculate({
        pickupLat:   Number(form.pickupLat),
        pickupLng:   Number(form.pickupLng),
        deliveryLat: Number(form.deliveryLat),
        deliveryLng: Number(form.deliveryLng),
        weightKg:    Number(form.weightKg),
      });
      setPrice(data.data);
    } catch {
      toast.error('Narxni hisoblashda xato');
    }
  }, [form]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await orderApi.create({
        ...form,
        pickupLat:   Number(form.pickupLat),
        pickupLng:   Number(form.pickupLng),
        deliveryLat: Number(form.deliveryLat),
        deliveryLng: Number(form.deliveryLng),
        weightKg:    Number(form.weightKg),
      });
      toast.success('Buyurtma yaratildi!');
      navigate(`/orders/${data.data.id}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xato yuz berdi');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      <h2 style={s.title}>Yangi buyurtma</h2>

      <form onSubmit={handleSubmit} style={s.card}>
        <Row>
          <Field label="Olib ketish manzili" required>
            <input style={s.input} value={form.pickupAddress} onChange={set('pickupAddress')}
              placeholder="Urganch, Al-Xorazmiy 12" required />
          </Field>
          <Field label="Yetkazish manzili" required>
            <input style={s.input} value={form.deliveryAddress} onChange={set('deliveryAddress')}
              placeholder="Xiva, Polvon Qori 5" required />
          </Field>
        </Row>

        <Row>
          <Field label="Pickup koordinata (lat, lng)">
            <div style={{ display:'flex', gap:8 }}>
              <input style={s.input} type="number" step="0.0001" value={form.pickupLat}
                onChange={set('pickupLat')} placeholder="41.5500" />
              <input style={s.input} type="number" step="0.0001" value={form.pickupLng}
                onChange={set('pickupLng')} placeholder="60.6200" />
            </div>
          </Field>
          <Field label="Delivery koordinata (lat, lng)">
            <div style={{ display:'flex', gap:8 }}>
              <input style={s.input} type="number" step="0.0001" value={form.deliveryLat}
                onChange={set('deliveryLat')} placeholder="41.3775" />
              <input style={s.input} type="number" step="0.0001" value={form.deliveryLng}
                onChange={set('deliveryLng')} placeholder="60.3619" />
            </div>
          </Field>
        </Row>

        <Row>
          <Field label="Og'irlik (kg)">
            <input style={s.input} type="number" min="0.1" step="0.5" value={form.weightKg}
              onChange={set('weightKg')} required />
          </Field>
          <Field label="Tavsif (ixtiyoriy)">
            <input style={s.input} value={form.description} onChange={set('description')}
              placeholder="Meva, 3 quti, ehtiyot bo'ling..." />
          </Field>
        </Row>

        <label style={s.checkLabel}>
          <input type="checkbox" checked={form.fragile} onChange={set('fragile')} />
          Mo'rt buyum (ehtiyot bo'lish kerak)
        </label>

        {price && (
          <div style={s.priceBox}>
            <div>
              <div style={s.priceLabel}>Hisoblangan narx</div>
              <div style={{ fontSize: 12, color: '#0F6E56', marginTop: 2 }}>
                {price.distanceKm} km · {form.weightKg} kg
                {price.isNightRate && ' · Tunda +30%'}
                {price.isBulkDiscount && ' · Ommaviy -15%'}
              </div>
            </div>
            <div style={s.priceValue}>{price.totalFee.toLocaleString()} so'm</div>
          </div>
        )}

        <div style={{ display:'flex', gap:10, marginTop:16 }}>
          <button type="button" style={s.btnSecondary} onClick={calcPrice}>
            Narx hisoblash
          </button>
          <button type="submit" style={s.btnPrimary} disabled={loading}>
            {loading ? 'Yuborilmoqda...' : '✓ Buyurtma berish'}
          </button>
        </div>
      </form>
    </div>
  );
}

function Row({ children }) {
  return <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14, marginBottom:14 }}>{children}</div>;
}
function Field({ label, children, required }) {
  return (
    <div>
      <label style={{ display:'block', fontSize:13, fontWeight:500, color:'#6b8080', marginBottom:5 }}>
        {label}{required && ' *'}
      </label>
      {children}
    </div>
  );
}

const s = {
  page:       { maxWidth: 720, margin: '24px auto', padding: '0 16px' },
  title:      { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:22, color:'#1a2e2a', marginBottom:16 },
  card:       { background:'#fff', border:'1px solid rgba(13,122,106,0.15)', borderRadius:16, padding:24 },
  input:      { width:'100%', padding:'10px 13px', border:'1px solid rgba(13,122,106,0.2)',
                borderRadius:9, fontSize:14, boxSizing:'border-box', outline:'none' },
  checkLabel: { display:'flex', alignItems:'center', gap:8, fontSize:14, color:'#444', cursor:'pointer' },
  priceBox:   { background:'#E1F5EE', border:'1px solid rgba(13,122,106,0.2)', borderRadius:12,
                padding:'14px 18px', display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:8 },
  priceLabel: { fontSize:13, color:'#085041', fontWeight:500 },
  priceValue: { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:22, color:'#085041' },
  btnPrimary: { flex:1, padding:'12px 0', background:'#0D7A6A', color:'#fff', border:'none',
                borderRadius:9, fontSize:14, fontWeight:600, cursor:'pointer' },
  btnSecondary:{ flex:1, padding:'12px 0', background:'transparent', color:'#0D7A6A',
                 border:'1px solid rgba(13,122,106,0.3)', borderRadius:9, fontSize:14, cursor:'pointer' },
};
